export function IcoEVChargingAvailability() {
  const { palette } = useIlloStyle();
  // 7-column weekly hours grid
  const days = 7;
  const cols = 4; // time slots per day
  return (
    <svg viewBox="0 0 200 130" preserveAspectRatio="xMidYMid slice" style={{ width: '100%', height: '100%' }}>
      <rect width="200" height="130" fill={palette.dark} />
      {/* Station header bar */}
      <rect x="20" y="16" width="160" height="16" rx="5" fill={palette.mid} opacity="0.20" />
      {/* Bolt icon in header */}
      <polygon points="97,19 91,27 95,27 89,33 103,25 99,25" fill={palette.accent} />
      {/* Peak availability badge */}
      <rect x="112" y="18" width="62" height="12" rx="4" fill={palette.accent} opacity="0.22" />
      <rect x="116" y="21" width="22" height="5" rx="2.5" fill={palette.accent} opacity="0.8" />
      <rect x="142" y="21" width="28" height="5" rx="2.5" fill={palette.mid} opacity="0.4" />
      {/* Weekly grid — 7 days × 4 slots */}
      {Array.from({ length: days }).map((_, di) =>
        Array.from({ length: cols }).map((_, si) => {
          const fill = Math.random() > 0.4; // static pattern
          const seed = (di * 4 + si) % 11;
          const isFull = seed < 5;
          return (
            <rect
              key={`${di}-${si}`}
              x={20 + di * 23 + si * 5}
              y={50 + si * 16}
              width="4" height="12" rx="2"
              fill={isFull ? palette.accent : palette.mid}
              opacity={isFull ? 0.70 : 0.20}
            />
          );
        })
      )}
    </svg>
  );
}
